#define _GNU_SOURCE
#include <dlfcn.h>
#include <stdarg.h>
#include <stdint.h>
#include <stdio.h>

int __isoc99_scanf(const char *fmt, ...) {
    static int (*real_scanf)(const char *, ...) = NULL;
    if (!real_scanf) real_scanf = dlsym(RTLD_NEXT, "__isoc99_scanf");

    va_list ap;
    va_start(ap, fmt);
    char *buf = va_arg(ap, char *);
    va_end(ap);

    int ret = real_scanf(fmt, buf);
    fprintf(stderr, "[scanlog] fmt=%s ret=%d buf=%p str='%s'\n", fmt, ret, (void *)buf, buf);
    return ret;
}

int printf(const char *fmt, ...) {
    static int (*real_vprintf)(const char *, va_list) = NULL;
    if (!real_vprintf) real_vprintf = dlsym(RTLD_NEXT, "vprintf");

    va_list ap;
    va_start(ap, fmt);
    fprintf(stderr, "[scanlog] printf fmt='%s'\n", fmt);
    va_list copy;
    va_copy(copy, ap);
    int ret = real_vprintf(fmt, copy);
    va_end(copy);
    va_end(ap);
    return ret;
}

